import{_ as a,o as i,c as t,ac as e}from"./chunks/framework.DnBnwVZk.js";const c=JSON.parse('{"title":"Ubuntu快捷方式(.desktop文件)与开机自启","description":"","frontmatter":{"date":"2022-04-05T10:59:40.000Z","categories":["Linux"],"tags":["Ubuntu","KDE","快捷方式"],"publish":true},"headers":[],"relativePath":"views/linux/UbuntuDesktopShortcut.md","filePath":"views/linux/UbuntuDesktopShortcut.md","lastUpdated":1775803235000}'),p={name:"views/linux/UbuntuDesktopShortcut.md"};function n(l,s,h,o,k,r){return i(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1649156380000"},[...s[0]||(s[0]=[e(`<h1 id="ubuntu快捷方式-desktop文件-与开机自启" tabindex="-1">Ubuntu快捷方式(.desktop文件)与开机自启 <a class="header-anchor" href="#ubuntu快捷方式-desktop文件-与开机自启" aria-label="Permalink to &quot;Ubuntu快捷方式(.desktop文件)与开机自启&quot;">​</a></h1><blockquote><p>注：以下说明在Kubuntu下确认OK，理论上Ubuntu原生(Gnome)也类似</p></blockquote><p>KUbuntu的快捷方式主要是.desktop文件方式存储，影响<strong>搜索</strong>，<strong>dock栏的快捷方式</strong>，同时还可以设置开机自启</p><h2 id="desktop文件的路径" tabindex="-1">.desktop文件的路径 <a class="header-anchor" href="#desktop文件的路径" aria-label="Permalink to &quot;.desktop文件的路径&quot;">​</a></h2><p>KUbuntu的desktop文件主要在下面几个地方，在任何一个地方存在(包括符号链接)，均会被系统扫描</p><ul><li>/usr/share/applications : 全局生效</li><li>~/.local/share/applications/ :一般情况下，此部分仅对对应用户生效</li><li>~/.config/autostart/:这个路径更多的是用来开机自启，但也有部分application是只定义在这里的，看各应用实现</li></ul><h2 id="desktop文件开机自启" tabindex="-1">.desktop文件开机自启 <a class="header-anchor" href="#desktop文件开机自启" aria-label="Permalink to &quot;.desktop文件开机自启&quot;">​</a></h2><p>如果上述路径里已有对应软件的.desktop文件，则仅需要在当前用户的配置文件夹新增一条<strong>符号链接</strong>即可，下面为将 utools设为开机自启的实例</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/share/applications/utools.desktop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/autostart/utools.desktop</span></span></code></pre></div><p><code>ln -s</code>命令的一般用法为<code>ln -s 源文件路径 要新增的符号链接路径</code></p><h2 id="手写-desktop文件" tabindex="-1">手写.desktop文件 <a class="header-anchor" href="#手写-desktop文件" aria-label="Permalink to &quot;手写.desktop文件&quot;">​</a></h2><p>如果某软件并未自带.desktop文件，比如AppImage格式的App，则需要手写.desktop文件，基本方式也比较简单</p><div class="language-desktop vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">desktop</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">[Desktop Entry]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Type=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Application  #不用改</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Name=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MyApp #显示名</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Path=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/home/xxx/myapp/ #app路径</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Exec=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/home/xxx/myapp/Downloaded.AppImage #要执行的命令</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Icon=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/home/xxx/myapp/Downloaded.png #icon图标</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Categories=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Tools #开始菜单的分类</span></span></code></pre></div><h2 id="discover取消代理设置" tabindex="-1">Discover取消代理设置 <a class="header-anchor" href="#discover取消代理设置" aria-label="Permalink to &quot;Discover取消代理设置&quot;">​</a></h2><p>这个是有解决方案的，就是很费劲。Discover 和 pkcon 是依赖 packagekit 的，这玩意是用 sql 存储配置的（在 /var/lib/PackageKit/transactions.db），你设置系统代理在哪儿设置都行，packagekit 会把代理写到 sql 里，你改代理也行，但是删代理删不了</p><p>于是解决方案就是用 sqlitebrowser 自己去数据库的 proxy 表里删…删完重启 packagekit service…</p><p><a href="https://forum.kde.org/viewtopic.php?f=309&amp;t=161739" target="_blank" rel="noreferrer">https://forum.kde.org/viewtopic.php?f=309&amp;t=161739</a></p><p>想自动删可以给你写一个 systemd timer，每隔一段时间去看看有没有 proxy 要是没有就去清空 proxy 表</p><p><a href="https://github.com/PackageKit/PackageKit/issues/392" target="_blank" rel="noreferrer">https://github.com/PackageKit/PackageKit/issues/392</a></p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sqlite3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sqlite3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/PackageKit/transactions.db</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DELETE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FROM</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> proxy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.exit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> packagekit</span></span></code></pre></div>`,20)])])}const u=a(p,[["render",n]]);export{c as __pageData,u as default};
